def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0.5
            continue
        if ratio > 3:
            priorities[i] = ratio ** 4
            continue
        total_score = 0
        for k in range(1, 6):
            term = ((-1) ** (k+1)) * (ratio ** k) / k
            total_score += term
            if total_score > 1:
                total_score /= 2
            elif total_score < -1:
                total_score *= -1
        multiplier = 1
        if 0 < ratio < 0.3:
            multiplier = 15
            for m in range(1, 4):
                multiplier += np.sin(ratio * m * np.pi)
        elif 0.3 <= ratio <= 0.6:
            multiplier = 7
            if ratio > 0.45:
                for n in range(1, 3):
                    multiplier *= (1 + 0.1 * n)
            else:
                multiplier /= 2
        else:
            multiplier = 3 + ratio
        priority_score = abs(total_score) * multiplier
        if capacity % 2 == 0 and item > capacity / 2:
            priority_score *= 1.2
        elif capacity % 3 == 0 and ratio < 0.8:
            priority_score *= 0.8
        priorities[i] = priority_score
    return priorities
